         if status.is_success() {
             let body = resp.text().await?;
             if body.is_empty() {
-                return Ok(serde_json::json!({}));
+                return Ok(T::default());
             }
             Ok(serde_json::from_str(&body)?)
         } else {
             self.handle_error(status, resp).await
         }
